    private void GetSkinsPackageOverrides()
    {
        List<List<string>> packagelists = new() { gamepackagesUni,
            gamepackagesOFB,
            gamepackagesNL,
            gamepackagesTSS,
            gamepackagesSeasons,
            gamepackagesPets,
            gamepackagesMSS,
            gamepackagesKBS,
            gamepackagesIKEA,
            gamepackagesHMSS,
            gamepackagesGLS,
            gamepackagesFT,
            gamepackagesFFS,
            gamepackagesCS,
            gamepackagesBV,
            gamepackagesAL,
            gamepackagesBase,
        };

        string outputfolder = @"O:\Godot Projects\SimsCCManager\src\SimsCCManager.App\Data\Overrides\Sims 2\specific";

        XmlSerializer serializer = new(typeof(SpecificOverrides));

        List<SpecificOverrides> specificOverrides = new();

        Parallel.ForEach(packagelists, packagelist =>
        {
            foreach (string file in packagelist)
            {
                if (file.Contains("Skins.package"))
                {
                    SimsPackageReader spr = new();
                    spr.ReadPackage(file);
                    
                    if (spr.Sims2Data.GZPSDataBlock.Count > 0)
                    {                    
                        foreach (GZPSData gzps in spr.Sims2Data.GZPSDataBlock)
                        {
                            SpecificOverrides over = new();
                            over.Description = gzps.Name;
                            if (gzps.Parts == "1" || gzps.Outfit == "1") { 
                                over.Type = "Hair"; 
                            } else if (gzps.Parts == "4" || gzps.Outfit == "4") { 
                                over.Type = "Clothing Top"; 
                            }  else if (gzps.Parts == "8" || gzps.Outfit == "8") { 
                                over.Type = "Clothing Body"; 
                            }  else if (gzps.Parts == "10" || gzps.Outfit == "10") { 
                                over.Type = "Clothing Bottom"; 
                            }
                            
                            SimsID id = new()
                            {
                                TypeID = gzps.TypeID,
                                InstanceID = gzps.InstanceID,
                                GroupID = gzps.GroupID
                            };
                            over.Entries.Add(id);

                            foreach(EIDRData ed in spr.Sims2Data.EIDRDataBlock.Where(x => x.GroupID == id.GroupID && x.InstanceID == id.InstanceID))
                            {
                                over.Entries.Add(new()
                                {
                                    TypeID = ed.TypeID,
                                    InstanceID = ed.InstanceID,
                                    GroupID = ed.GroupID
                                });
                            }   

                            specificOverrides.Add(over);                            
                        }                    
                    }
                    
                    if (spr.Sims2Data.XTOLDataBlock.Count > 0)
                    {
                        foreach (XTOLData xtol in spr.Sims2Data.XTOLDataBlock)
                        {
                            SpecificOverrides over = new();
                            over.Description = xtol.Name;
                            over.Type = "Makeup";
                            
                            SimsID id = new()
                            {
                                TypeID = xtol.TypeID,
                                InstanceID = xtol.InstanceID,
                                GroupID = xtol.GroupID
                            };
                            over.Entries.Add(id);

                            foreach(EIDRData ed in spr.Sims2Data.EIDRDataBlock.Where(x => x.GroupID == id.GroupID && x.InstanceID == id.InstanceID))
                            {
                                over.Entries.Add(new()
                                {
                                    TypeID = ed.TypeID,
                                    InstanceID = ed.InstanceID,
                                    GroupID = ed.GroupID
                                });
                            }   

                            specificOverrides.Add(over);                            
                        } 
                    }
                }
                
            }
        });

        /*string original = @"O:\Godot Projects\SimsCCManager\src\SimsCCManager.App\Data\Overrides\Sims 2\specific";
        string[] xmls = [..Directory.EnumerateFiles(original)];
        outputfolder = @"O:\Godot Projects\SimsCCManager\src\SimsCCManager.App\Data\Overrides\Sims 2\specific\tidied";

        serializer = new(typeof(SpecificOverrides));

        List<SpecificOverrides> specificOverrides = new();

        foreach (string xml in xmls)
        {
            SpecificOverrides so = new();
            using (FileStream fileStream = new(xml, FileMode.Open, System.IO.FileAccess.Read)){
                using (StreamReader streamReader = new(fileStream)){
                    so = (SpecificOverrides)serializer.Deserialize(streamReader);
                    streamReader.Close();
                }
                fileStream.Close();
            }
            specificOverrides.Add(so);
        }*/

        List<SimsID> entries = [..specificOverrides.SelectMany(x => x.Entries)];
        List<string> instanceids = [..entries.Select(e => e.InstanceID)];
        
        Parallel.ForEach(instanceids, inid => 
        {
            SpecificOverrides specific = new();
            List<SpecificOverrides> specov = [..specificOverrides.Where(x => x.Entries.Any(e => e.InstanceID == inid))];
            foreach (SpecificOverrides so in specov)
            {
                foreach (SimsID entry in so.Entries)
                {
                    if (!specific.Entries.Contains(entry)) specific.Entries.Add(entry);
                }   
                if (so.Type == "Hair")
                {
                    specific.Type = "Hair";
                    specific.Description = so.Description;
                } else if (so.Type == "Clothing Body")
                {
                    specific.Type = "Clothing Body";
                    specific.Description = so.Description;
                } else if (so.Type == "Clothing Top")
                {
                    specific.Type = "Clothing Top";
                    specific.Description = so.Description;
                } else if (so.Type == "Clothing Bottom")
                {
                    specific.Type = "Clothing Bottom";
                    specific.Description = so.Description;
                } else if (so.Type == "Makeup")
                {
                    specific.Type = "Makeup";
                    specific.Description = so.Description;
                }
            }

            string output = Path.Combine(outputfolder, string.Format("{0} {1}.xml", specific.Type, specific.Description));

            try
            {
                locker.AcquireWriterLock(int.MaxValue);
                using (var writer = new StreamWriter(output))
                {
                    serializer.Serialize(writer, specific);
                }
            } finally
            {
                locker.ReleaseWriterLock();
            }

            
        });
    }

    static ReaderWriterLock locker = new ReaderWriterLock();

