    private List<SimsOverrides> GetInfo(SimsPackageReader pr)
    {      
        List<SimsOverrides> overrides = new();
        //overrides.FileLocation = pr.fileinfo.FullName;
        
        if (GlobalVariables.DebugMode) Logging.WriteDebugLog(string.Format("Reading pr: {0}", pr.fileinfo.Name));
        if (pr.Sims2Data != null) {
            if (pr.Sims2Data.OBJDDataBlock.Count > 0)
            {
                foreach (OBJDData block in pr.Sims2Data.OBJDDataBlock)
                {
                    if (!string.IsNullOrEmpty(block.ObjectGUID))
                    {
                        SimsOverrides so = new();
                        so.FileLocation = pr.fileinfo.FullName;
                        ItemOverride io = new();
                        SimsID id = new();
                        id.KeyFromEntry(block);
                        io.Overridden = RemoveInvalidXmlChars(block.ObjectGUID);
                        io.ID = id;
                        so.GuidOverrides.Add(io);
                        overrides.Add(so);
                    }                    
                } 
            }
            if (pr.Sims2Data.XOBJDataBlock.Count > 0)
            {
                foreach (XOBJData block in pr.Sims2Data.XOBJDataBlock)
                {
                    if (!string.IsNullOrEmpty(block.ObjectGUID)) {
                        SimsOverrides so = new();
                        so.FileLocation = pr.fileinfo.FullName;
                        ItemOverride io = new();
                        SimsID id = new();
                        id.KeyFromEntry(block);
                        io.Overridden = RemoveInvalidXmlChars(block.ObjectGUID);
                        io.ID = id;
                        so.GuidOverrides.Add(io);
                        overrides.Add(so);
                    }                        
                } 
            }
            if (pr.Sims2Data.TXMTDataBlock.Count > 0)
            {
                foreach (TXMTData block in pr.Sims2Data.TXMTDataBlock)
                {
                    if (!string.IsNullOrEmpty(block.FileName))
                    {
                        SimsOverrides so = new();
                        so.FileLocation = pr.fileinfo.FullName;
                        ItemOverride io = new();
                        SimsID id = new();
                        id.KeyFromEntry(block);
                        io.Overridden = RemoveInvalidXmlChars(block.FileName);
                        io.ID = id;
                        so.FileNameOverrides.Add(io);
                        overrides.Add(so);
                    } 
                    if (block.MaterialProperties.Any(x => x.PropertyName=="stdMatBaseTextureName"))
                    {
                        SimsOverrides so = new();
                        so.FileLocation = pr.fileinfo.FullName;
                        ItemOverride io = new();
                        SimsID id = new();
                        id.KeyFromEntry(block);
                        io.Overridden = RemoveInvalidXmlChars(block.MaterialProperties.First(x => x.PropertyName=="stdMatBaseTextureName").PropertyValue);
                        io.ID = id;
                        so.TextureNameOverrides.Add(io);
                        overrides.Add(so);
                    }
                    if (!string.IsNullOrEmpty(block.MaterialDescription))
                    {       
                        SimsOverrides so = new();
                        so.FileLocation = pr.fileinfo.FullName;                 
                        ItemOverride io = new();
                        SimsID id = new();
                        id.KeyFromEntry(block);
                        io.ID = id;
                        io.Overridden = RemoveInvalidXmlChars(block.MaterialDescription);
                        so.References.Add(io);
                        overrides.Add(so);                
                    }                    
                } 
            }
            if (pr.Sims2Data.MMATDataBlock.Count > 0)
            {
                foreach (MMATData block in pr.Sims2Data.MMATDataBlock)
                {
                    if (!string.IsNullOrEmpty(block.ObjectGUID))
                    {
                        SimsOverrides so = new();
                        so.FileLocation = pr.fileinfo.FullName;  
                        ItemOverride io = new();
                        SimsID id = new();
                        id.KeyFromEntry(block);
                        io.Overridden = RemoveInvalidXmlChars(block.ObjectGUID);
                        io.ID = id;
                        so.GuidOverrides.Add(io);
                        overrides.Add(so);
                    }                 
                } 
            }
            if (pr.Sims2Data.SHPEDataBlock.Count > 0)
            {
                foreach (SHPEData block in pr.Sims2Data.SHPEDataBlock)
                {
                    if (!string.IsNullOrEmpty(block.FileName))
                    {
                        SimsOverrides so = new();
                        so.FileLocation = pr.fileinfo.FullName;  
                        ItemOverride io = new();
                        SimsID id = new();
                        id.KeyFromEntry(block);
                        io.Overridden = RemoveInvalidXmlChars(block.FileName);
                        io.ID = id;
                        so.FileNameOverrides.Add(io);
                        overrides.Add(so);
                    }                     
                } 
            }
            if (pr.Sims2Data.TXTRDataBlock.Count > 0)
            {
                foreach (TXTRData block in pr.Sims2Data.TXTRDataBlock)
                {
                    if (!string.IsNullOrEmpty(block.FullTXTRName))
                    {
                        SimsOverrides so = new();
                        so.FileLocation = pr.fileinfo.FullName;  
                        ItemOverride io = new();
                        SimsID id = new();
                        id.KeyFromEntry(block);
                        io.Overridden = RemoveInvalidXmlChars(block.FullTXTRName);
                        io.ID = id;
                        so.TextureNameOverrides.Add(io);
                        overrides.Add(so);
                    } 
                    if (!string.IsNullOrEmpty(block.GUID))
                    {
                        SimsOverrides so = new();
                        so.FileLocation = pr.fileinfo.FullName;                         
                        ItemOverride io = new();
                        SimsID id = new();
                        id.KeyFromEntry(block);
                        io.Overridden = RemoveInvalidXmlChars(block.GUID);
                        io.ID = id;
                        so.GuidOverrides.Add(io);
                        overrides.Add(so);
                    }                     
                } 
            }  
            if (pr.Sims2Data.IndexEntries.Count > 0)
            {
                foreach (IndexEntry entry in pr.Sims2Data.IndexEntries)
                {
                    SimsOverrides so = new();                    
                    SimsID id = new();
                    id.KeyFromIndexEntry(entry);
                    so.FileLocation = pr.fileinfo.FullName; 
                    so.Entries.Add(id);
                    if (!overrides.Any(o => o.FileNameOverrides.Any(x => x.ID.FullKey == id.FullKey)) && !overrides.Any(o => o.TextureNameOverrides.Any(x => x.ID.FullKey == id.FullKey)) && !overrides.Any(o => o.GuidOverrides.Any(x => x.ID.FullKey == id.FullKey)) && !overrides.Any(o => o.References.Any(x => x.ID.FullKey == id.FullKey))) {
                        if (GlobalVariables.DebugMode) Logging.WriteDebugLog(string.Format("Adding key {0} to file {1}", id.FullKey, so.FileLocation));
                        overrides.Add(so);
                    } else
                    {
                        if (GlobalVariables.DebugMode) Logging.WriteDebugLog(string.Format("{0} exists as another type. Not adding alone to {1}.", id.FullKey, so.FileLocation));
                    }
                }
            }
        }          
        
        return overrides;
        
    }

    public static string RemoveInvalidXmlChars(string content)
    {
    return new string(content.Where(ch => System.Xml.XmlConvert.IsXmlChar(ch)).ToArray());
    }

    

